// @ts-nocheck
import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { useWorkspaceStore } from '../../store/workspace';

const WAIT_HEX: Record<string, string> = {
  CPU: '#f97316', Lock: '#ef4444', LWLock: '#eab308', IO: '#3b82f6',
  BufferPin: '#a855f7', Client: '#94a3b8', IPC: '#06b6d4', Timeout: '#f43f5e', Other: '#0ea5e9',
};

const WINDOWS = ['15m', '30m', '1h', '6h', '24h', '7d', '30d'] as const;
type W = typeof WINDOWS[number];

function fmtNum(n: number) {
  if (n >= 1e6) return `${(n / 1e6).toFixed(1)}M`;
  if (n >= 1e3) return `${(n / 1e3).toFixed(1)}K`;
  return String(Math.round(n));
}

function fmtBucketLabel(ts: string, windowLabel: string) {
  const d = new Date(ts);
  if (windowLabel === '7d' || windowLabel === '30d') {
    return d.toLocaleDateString([], { month: 'short', day: 'numeric' });
  }
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function Loading() { return <div className="text-2xs text-nv-textMuted py-6 text-center animate-pulse">Loading…</div>; }
function Empty({ msg }: { msg: string }) { return <div className="text-2xs text-nv-textSubtle py-4 text-center">{msg}</div>; }

function WaitTrendLine({ trend, windowLabel, color }: { trend: { ts: string; samples: number }[]; windowLabel: string; color: string }) {
  if (!trend.length) return <Empty msg="No wait samples in this window." />;
  const W = 800, H = 120, padL = 36, padR = 12, padT = 8, padB = 22;
  const cw = W - padL - padR, ch = H - padT - padB;
  const max = Math.max(...trend.map((r) => r.samples), 0.1);
  const slot = cw / trend.length;
  const barW = Math.min(slot * 0.75, 24);

  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={H} preserveAspectRatio="none" className="block">
      {[0, 0.5, 1].map((f, i) => {
        const y = padT + ch - f * ch;
        return (
          <g key={i}>
            <line x1={padL} y1={y} x2={W - padR} y2={y} stroke="#1f2937" strokeWidth={1} />
            <text x={padL - 4} y={y + 3} textAnchor="end" fontSize={9} fill="#64748b">{(max * f).toFixed(max < 10 ? 1 : 0)}</text>
          </g>
        );
      })}
      {trend.map((r, i) => {
        const h = (r.samples / max) * ch;
        const x = padL + slot * i + (slot - barW) / 2;
        const y = padT + ch - h;
        return <rect key={r.ts} x={x} y={y} width={barW} height={h} fill={color} opacity={0.9} rx={1} />;
      })}
      {trend.filter((_, i) => i % Math.ceil(trend.length / 8) === 0 || i === trend.length - 1).map((r) => {
        const i = trend.indexOf(r);
        const x = padL + slot * (i + 0.5);
        return <text key={r.ts} x={x} y={H - 4} textAnchor="middle" fontSize={8} fill="#64748b">{fmtBucketLabel(r.ts, windowLabel)}</text>;
      })}
    </svg>
  );
}

function TopTypesChart({ rows, color }: { rows: { waitType: string; samples: number; totalMs?: number }[]; color: string }) {
  if (!rows.length) return <Empty msg="No wait types recorded." />;
  const max = Math.max(...rows.map((r) => r.samples), 1);
  return (
    <div className="space-y-1.5">
      {rows.slice(0, 10).map((r, i) => (
        <div key={i}>
          <div className="flex justify-between text-2xs mb-0.5">
            <span className="text-nv-text font-mono truncate max-w-[70%]" title={r.waitType}>{r.waitType}</span>
            <span className="text-nv-textSubtle font-mono">{fmtNum(r.samples)}</span>
          </div>
          <div className="h-2.5 bg-nv-border/40 rounded-sm overflow-hidden">
            <div className="h-full rounded-sm" style={{ width: `${(r.samples / max) * 100}%`, background: color }} />
          </div>
        </div>
      ))}
    </div>
  );
}

function AdvisorCard({ a }: { a: { severity: string; title: string; message: string } }) {
  const cls = a.severity === 'critical' ? 'border-red-700/60 bg-red-950/20 text-red-300'
    : a.severity === 'high' ? 'border-orange-700/50 bg-orange-950/15 text-orange-300'
    : a.severity === 'warning' ? 'border-amber-700/50 bg-amber-950/15 text-amber-300'
    : 'border-nv-border bg-nv-surface/30 text-nv-text';
  return (
    <div className={`p-2 rounded border text-2xs mb-2 ${cls}`}>
      <div className="font-medium">{a.title}</div>
      <p className="text-nv-textMuted mt-0.5">{a.message}</p>
    </div>
  );
}

function LiveBlockingSection({ data }: { data: any }) {
  const roots: any[] = data?.roots ?? [];
  if (!roots.length) return <Empty msg="No active blocking chains right now." />;
  return (
    <div className="space-y-2 max-h-56 overflow-auto">
      {roots.map((root, i) => (
        <div key={i} className="border border-orange-700/40 rounded-md overflow-hidden">
          <div className="px-2 py-1.5 bg-orange-900/20 text-2xs">
            <span className="text-orange-400 font-semibold">Blocker PID {root.blockerPid ?? root.blocker_pid}</span>
            <span className="text-nv-textMuted ml-2">{root.blockerUser ?? root.blocker_user}</span>
          </div>
          {(root.victims ?? []).slice(0, 4).map((v: any, j: number) => (
            <div key={j} className="px-2 py-1 border-t border-nv-border/40 text-[10px] font-mono text-nv-textSubtle truncate">
              ↳ PID {v.blocked_pid}: {(v.blocked_query ?? '').slice(0, 120) || '—'}
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

export function WaitDetailPanel({
  connectionId,
  connectionName,
  waitClass,
}: {
  connectionId: string;
  connectionName?: string;
  waitClass: string;
}) {
  const [window, setWindow] = useState<W>('1h');
  const qc = useQueryClient();
  const color = WAIT_HEX[waitClass] ?? WAIT_HEX.Other;

  const detail = useQuery({
    queryKey: ['wait-detail', connectionId, waitClass, window],
    queryFn: () => api.dpaWaitDetail(connectionId, waitClass, window),
    enabled: !!waitClass,
    staleTime: 20000,
  });

  const d = detail.data;

  function openQuery(queryId: string, label: string) {
    useWorkspaceStore.getState().openTab({
      type: 'queryDetail',
      title: `Query · ${label.slice(0, 40)}`,
      connectionId,
      connectionName,
      queryId,
    });
  }

  function refresh() {
    qc.invalidateQueries({ queryKey: ['wait-detail', connectionId, waitClass] });
  }

  return (
    <div className="h-full flex flex-col text-xs">
      <div className="px-3 py-2 border-b border-nv-border flex items-center gap-2 flex-wrap shrink-0 bg-gradient-to-r from-slate-950 to-orange-950/20">
        <span className="inline-block w-3 h-3 rounded-sm" style={{ background: color }} />
        <span className="font-semibold text-nv-text">Wait Analysis · {waitClass}</span>
        {connectionName && <span className="text-nv-textMuted">· {connectionName}</span>}
        <div className="ml-auto flex items-center gap-1 flex-wrap">
          {WINDOWS.map((wk) => (
            <button key={wk} type="button" onClick={() => setWindow(wk)}
              className={`nv-btn !py-0.5 !text-2xs ${window === wk ? 'bg-orange-900/40 text-orange-200' : ''}`}>{wk}</button>
          ))}
          <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={refresh}>↻</button>
        </div>
      </div>

      {detail.isLoading && <Loading />}
      {!detail.isLoading && d && (
        <div className="flex-1 overflow-auto p-3 space-y-4">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            <div className="rounded border border-nv-border p-2 bg-nv-panel/60">
              <div className="text-2xs text-nv-textSubtle">Total samples</div>
              <div className="text-lg font-bold font-mono" style={{ color }}>{fmtNum(d.totalSamples ?? 0)}</div>
            </div>
            <div className="rounded border border-nv-border p-2 bg-nv-panel/60">
              <div className="text-2xs text-nv-textSubtle">Bucket size</div>
              <div className="text-lg font-bold font-mono text-nv-text">{d.bucket ?? '—'}</div>
            </div>
            <div className="rounded border border-nv-border p-2 bg-nv-panel/60">
              <div className="text-2xs text-nv-textSubtle">Wait types</div>
              <div className="text-lg font-bold font-mono text-nv-text">{d.topTypes?.length ?? 0}</div>
            </div>
            <div className="rounded border border-nv-border p-2 bg-nv-panel/60">
              <div className="text-2xs text-nv-textSubtle">Blocking events</div>
              <div className={`text-lg font-bold font-mono ${(d.blockingEvents?.length ?? 0) > 0 ? 'text-red-400' : 'text-green-400'}`}>
                {d.blockingEvents?.length ?? 0}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Wait trend ({window})</p>
              <WaitTrendLine trend={d.trend ?? []} windowLabel={window} color={color} />
            </div>
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Top wait events</p>
              <TopTypesChart rows={d.topTypes ?? []} color={color} />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Recommendations</p>
              {!(d.advisors?.length) && <Empty msg="No specific recommendations for this wait class." />}
              {(d.advisors ?? []).map((a: any, i: number) => <AdvisorCard key={i} a={a} />)}
            </div>
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Queries causing this wait</p>
              {!(d.topQueries?.length) && <Empty msg="No per-query wait correlation yet." />}
              <div className="space-y-1 max-h-52 overflow-auto">
                {(d.topQueries ?? []).map((q: any, i: number) => (
                  <button key={i} type="button"
                    className="w-full text-left px-2 py-1.5 rounded border border-nv-border/40 hover:bg-sky-950/20 hover:border-sky-800/40 transition-colors"
                    onClick={() => q.queryId && openQuery(String(q.queryId), String(q.text ?? ''))}>
                    <div className="flex justify-between gap-2 text-2xs">
                      <span className="text-nv-textSubtle font-mono shrink-0">{fmtNum(q.samples)} samples</span>
                      <span className="text-nv-textSubtle truncate">{q.waitType}</span>
                    </div>
                    <p className="text-[10px] font-mono text-nv-textMuted truncate mt-0.5">{q.text}</p>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {['Lock', 'LWLock', 'Timeout'].includes(waitClass) && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
              <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
                <p className="font-medium text-nv-text mb-2">Live blocking</p>
                <LiveBlockingSection data={d.liveBlocking} />
              </div>
              <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
                <p className="font-medium text-nv-text mb-2">Blocking history ({window})</p>
                {!(d.blockingEvents?.length) && <Empty msg="No blocking events in window." />}
                <div className="space-y-1 max-h-52 overflow-auto">
                  {(d.blockingEvents ?? []).map((e: any) => (
                    <div key={e.id} className="px-2 py-1 rounded border border-nv-border/40 bg-nv-surface/30 text-2xs">
                      <div className="flex items-center gap-2">
                        <span className={`font-medium ${e.severity === 'critical' ? 'text-red-400' : 'text-orange-400'}`}>{e.eventType}</span>
                        <span className="text-nv-textSubtle ml-auto">{e.timestamp ? new Date(e.timestamp).toLocaleString() : ''}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
